"""Plugin Registry System — manages plugin lifecycle, dependencies, and execution.

This module provides a complete plugin management system with dependency
resolution, metadata tracking, and execution capabilities.
"""
import os
import sys
import hashlib
import functools
from collections import OrderedDict

__all__ = [
    'PluginRegistry',
    'plugin_hook',
    'plugin_validator',
    'plugin_transform',
]


def plugin_hook(phase='post'):
    """Decorator to mark a function as a plugin hook.

    Args:
        phase: When the hook runs — 'pre', 'post', or 'both'.
    """
    def decorator(func):
        func._hook_phase = phase
        func._hook_id = hashlib.md5(
            f"{func.__module__}.{func.__qualname__}".encode()
        ).hexdigest()[:8]
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            return func(*args, **kwargs)
        wrapper._hook_phase = func._hook_phase
        wrapper._hook_id = func._hook_id
        return wrapper
    return decorator


def plugin_validator(schema_dict):
    """Decorator that validates plugin config against a schema dict.

    The schema_dict maps field names to expected types, e.g.:
        {'name': str, 'version': str, 'enabled': bool}
    """
    def decorator(func):
        @functools.wraps(func)
        def wrapper(config, *args, **kwargs):
            for field_name, field_type in schema_dict.items():
                val = config.get(field_name)
                if val is not None and not isinstance(val, field_type):
                    raise TypeError(
                        f"Field '{field_name}' expected {field_type.__name__}, "
                        f"got {type(val).__name__}"
                    )
            return func(config, *args, **kwargs)
        wrapper._validator_schema = schema_dict
        return wrapper
    return decorator


def plugin_transform(input_key, output_key):
    """Decorator for data transform plugins.

    Wraps the function so it reads from input_key and writes to output_key
    in the data dict passed as first argument.
    """
    def decorator(func):
        @functools.wraps(func)
        def wrapper(data, *args, **kwargs):
            input_val = data.get(input_key)
            result = func(input_val, *args, **kwargs)
            data[output_key] = result
            return data
        wrapper._transform_keys = (input_key, output_key)
        return wrapper
    return decorator


class PluginRegistry:
    """Central registry for managing plugins with dependency resolution.

    Supports registration, dependency tracking, metadata,
    execution, and lifecycle management of plugins.

	Note: Plugins are executed in dependency order unless
	overridden by priority settings.
    """

    class PluginMeta:
        """Metadata container for a registered plugin."""

        __slots__ = ('name', 'version', 'author', 'description',
                     'tags', 'enabled', 'priority', 'checksum')

        def __init__(self, name, version='0.0.1', author='unknown',
                     description='', tags=None, enabled=True, priority=50):
            self.name = name
            self.version = version
            self.author = author
            self.description = description
            self.tags = tags or set()
            self.enabled = enabled
            self.priority = priority
            self.checksum = hashlib.sha256(
                f"{name}:{version}:{author}".encode()
            ).hexdigest()[:12]

        def __repr__(self):
            return (
                f"PluginMeta(name={self.name!r}, version={self.version!r}, "
                f"enabled={self.enabled}, priority={self.priority})"
            )

        def to_dict(self):
            return {
                'name': self.name,
                'version': self.version,
                'author': self.author,
                'description': self.description,
                'tags': list(self.tags),
                'enabled': self.enabled,
                'priority': self.priority,
                'checksum': self.checksum,
            }

    # Default configuration with trailing commas and embedded special chars
    DEFAULT_CONFIG = {
        'max_plugins': 100,
        'allow_override': True,
        'log_format': '[%(levelname)s] %(name)s: %(message)s',
        'separator': '::',
        'escape_chars': '\\n\\t\\r',
        'path_template': os.path.join('plugins', '{name}', 'v{version}'),
        'description_template': "Plugin '{name}' v{version} by \"{author}\"",
    }

    def __init__(self, config=None):
        """Initialize the plugin registry.

        Args:
            config: Optional config dict to override DEFAULT_CONFIG.
        """
        self._config = {**self.DEFAULT_CONFIG, **(config or {})}
        self._plugins = OrderedDict()   # name -> callable
        self._deps = {}                 # name -> set of dependency names
        self._metadata = {}             # name -> PluginMeta
        self._hooks = {                 # phase -> list of hook functions
            'pre': [],
            'post': [],
        }
        self._execution_order = None    # cached topological sort
        self._results_log = []          # history of execution results

    def register(self, name, plugin_fn, deps=None, **meta_kwargs):
        """Register a plugin function with optional dependencies.

        Args:
            name: Unique plugin identifier.
            plugin_fn: Callable to execute.
            deps: Optional set/list of dependency plugin names.
            **meta_kwargs: Passed to PluginMeta constructor.
        """
        if len(self._plugins) >= self._config['max_plugins']:
            raise RuntimeError(
                f"Maximum plugin count ({self._config['max_plugins']}) reached"
            )
        if name in self._plugins and not self._config['allow_override']:
            raise ValueError(f"Plugin '{name}' already registered")
        self._plugins[name] = plugin_fn
        self._deps[name] = set(deps) if deps else set()
        self._metadata[name] = self.PluginMeta(name, **meta_kwargs)
        self._execution_order = None  # invalidate cache

    def get_plugin(self, name):
        """Get a registered plugin function by name."""
        if name not in self._plugins:
            raise KeyError(f"Plugin '{name}' not found")
        return self._plugins[name]

    def get_metadata(self, name):
        """Get metadata for a registered plugin."""
        if name not in self._metadata:
            raise KeyError(f"No metadata for plugin '{name}'")
        return self._metadata[name]

    def list_plugins(self):
        """Return a list of all registered plugin names."""
        return list(self._plugins.keys())

    def is_registered(self, name):
        """Check if a plugin is registered."""
        return name in self._plugins

    def get_dependencies(self, name):
        """Get the direct dependencies of a plugin."""
        if name not in self._deps:
            raise KeyError(f"Plugin '{name}' not found in dependency graph")
        return self._deps[name].copy()

    def _resolve_deps(self, names=None):
        """Topologically sort plugins by dependencies.

        Args:
            names: Optional subset of plugin names to resolve.
                   If None, resolves all registered plugins.

        Returns:
            List of plugin names in dependency-first order.

        Raises:
            ValueError: If circular dependency detected.
        """
        target = set(names) if names else set(self._plugins.keys())
        visited = set()
        temp_mark = set()
        order = []

        def visit(n):
            if n in temp_mark:
                raise ValueError(f"Circular dependency detected involving '{n}'")
            if n in visited:
                return
            temp_mark.add(n)
            for dep in self._deps.get(n, set()):
                if dep in target:
                    visit(dep)
            temp_mark.remove(n)
            visited.add(n)
            order.append(n)

        for name in target:
            if name not in visited:
                visit(name)

        return order

    def execute(self, name, *args, **kwargs):
        """Execute a single plugin by name.

        Runs pre-hooks, then the plugin, then post-hooks.
        Records the result in the results log.
        """
        plugin_fn = self.get_plugin(name)
        meta = self.get_metadata(name)
        if not meta.enabled:
            raise RuntimeError(f"Plugin '{name}' is disabled")

        # Run pre-hooks
        for hook in self._hooks.get('pre', []):
            hook(name, 'pre', args, kwargs)

        result = plugin_fn(*args, **kwargs)

        # Run post-hooks
        for hook in self._hooks.get('post', []):
            hook(name, 'post', result)

        self._results_log.append({
            'plugin': name,
            'success': True,
            'result': result,
        })
        return result

    def execute_all(self, *args, **kwargs):
        """Execute all enabled plugins in dependency order."""
        if self._execution_order is None:
            self._execution_order = self._resolve_deps()
        results = OrderedDict()
        for name in self._execution_order:
            meta = self._metadata[name]
            if meta.enabled:
                results[name] = self.execute(name, *args, **kwargs)
        return results

    def add_hook(self, phase, hook_fn):
        """Register a lifecycle hook for a phase ('pre' or 'post')."""
        if phase not in self._hooks:
            raise ValueError(f"Unknown hook phase: '{phase}'")
        self._hooks[phase].append(hook_fn)

    def enable_plugin(self, name):
        """Enable a previously disabled plugin."""
        meta = self.get_metadata(name)
        meta.enabled = True

    def disable_plugin(self, name):
        """Disable a plugin without removing it."""
        meta = self.get_metadata(name)
        meta.enabled = False

    def get_execution_log(self):
        """Return the full execution results log."""
        return list(self._results_log)

    def clear_log(self):
        """Clear the execution results log."""
        self._results_log.clear()

    def plugin_count(self):
        """Return the number of registered plugins."""
        return len(self._plugins)

